import{_ as e,o as a,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const f=JSON.parse('{"title":"刻印（Engravings）概要","description":"","frontmatter":{},"headers":[],"relativePath":"ja/engravings/index.md","filePath":"ja/engravings/index.md","lastUpdated":1775394001000}'),i={name:"ja/engravings/index.md"};function n(d,t,s,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="刻印-engravings-概要" tabindex="-1">刻印（Engravings）概要 <a class="header-anchor" href="#刻印-engravings-概要" aria-label="Permalink to &quot;刻印（Engravings）概要&quot;">​</a></h1><p><strong>刻印</strong>は覚醒体にサブステータスを付与する強化システムです。刻印の厳選は終盤コンテンツの攻略に不可欠な要素です。</p><h2 id="基本情報" tabindex="-1">基本情報 <a class="header-anchor" href="#基本情報" aria-label="Permalink to &quot;基本情報&quot;">​</a></h2><ul><li>覚醒体に刻印を装備してサブステータスを付与</li><li>刻印にはメインステータスとサブステータスが存在</li><li>サブステータスはランダムに決定される（厳選要素）</li></ul><h2 id="刻印のステータス" tabindex="-1">刻印のステータス <a class="header-anchor" href="#刻印のステータス" aria-label="Permalink to &quot;刻印のステータス&quot;">​</a></h2><h3 id="メインステータス" tabindex="-1">メインステータス <a class="header-anchor" href="#メインステータス" aria-label="Permalink to &quot;メインステータス&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">スロット</th><th style="text-align:left;">付与可能なメインステータス</th></tr></thead><tbody><tr><td style="text-align:center;"><em>準備中...</em></td><td style="text-align:left;">—</td></tr></tbody></table><h3 id="サブステータス" tabindex="-1">サブステータス <a class="header-anchor" href="#サブステータス" aria-label="Permalink to &quot;サブステータス&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">サブステータス</th><th style="text-align:left;">効果</th></tr></thead><tbody><tr><td style="text-align:left;">攻撃力%</td><td style="text-align:left;">攻撃力を割合で上昇</td></tr><tr><td style="text-align:left;">HP%</td><td style="text-align:left;">HPを割合で上昇</td></tr><tr><td style="text-align:left;">防御力%</td><td style="text-align:left;">防御力を割合で上昇</td></tr><tr><td style="text-align:left;">速度</td><td style="text-align:left;">速度を固定値で上昇</td></tr><tr><td style="text-align:left;">狂気蓄積率</td><td style="text-align:left;">狂気ゲージの蓄積速度を上昇</td></tr><tr><td style="text-align:left;">会心率</td><td style="text-align:left;">クリティカル発生率を上昇</td></tr><tr><td style="text-align:left;">会心ダメージ</td><td style="text-align:left;">クリティカルダメージ倍率を上昇</td></tr></tbody></table><h2 id="刻印の強化" tabindex="-1">刻印の強化 <a class="header-anchor" href="#刻印の強化" aria-label="Permalink to &quot;刻印の強化&quot;">​</a></h2><p><em>準備中...</em></p><h2 id="厳選のポイント" tabindex="-1">厳選のポイント <a class="header-anchor" href="#厳選のポイント" aria-label="Permalink to &quot;厳選のポイント&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>攻撃型覚醒体は「攻撃力%」「会心率」「会心ダメージ」のサブステを優先しましょう。防御型は「HP%」「防御力%」が重要です。</p></div><h2 id="入手方法" tabindex="-1">入手方法 <a class="header-anchor" href="#入手方法" aria-label="Permalink to &quot;入手方法&quot;">​</a></h2><ul><li><strong>チャレンジステージ</strong> — 高レアリティ刻印がドロップ</li><li><strong>冶錬室</strong> — 不要な刻印を変換</li><li><strong>イベント報酬</strong> — 期間限定で入手可能</li></ul><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./list.html">刻印一覧</a></li><li><a href="./../covenants/">密契概要</a></li><li><a href="./../awakeners/leveling.html">育成ガイド</a></li></ul>',17)])])}const x=e(i,[["render",n]]);export{f as __pageData,x as default};
